#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<long long> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    auto is_min_heap = [&](vector<long long>& nums){
        int n = nums.size();
        for(int i = 0; i < n; i++){
            int left_child = 2 * i + 1;
            int right_child = 2 * i + 2;
            if(left_child < n && nums[i] > nums[left_child]) return false;
            if(right_child < n && nums[i] > nums[right_child]) return false;
        }
        return true;
    };
    cout << (is_min_heap(nums) ? "True" : "False") << endl;
    return 0;
}
